"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[387],{1502(t,e,d){d.r(e),d.d(e,{comp:()=>n,data:()=>r});var i=d(641);const a={},n=(0,d(6262).A)(a,[["render",function(t,e){return(0,i.uX)(),(0,i.CE)("div",null,[...e[0]||(e[0]=[(0,i.Fv)('<h1 id="auction-types" tabindex="-1"><a class="header-anchor" href="#auction-types"><span>Auction Types</span></a></h1><p>Ten formats. Each one is configured per-auction (not site-wide), so you can run any mix simultaneously.</p><p>Enable / disable types globally in <strong><a href="/admin-settings.html#auction-types" target="_blank" rel="noopener noreferrer">Settings → Auction Types</a></strong>.</p><h2 id="quick-comparison" tabindex="-1"><a class="header-anchor" href="#quick-comparison"><span>Quick comparison</span></a></h2><table><thead><tr><th>Type</th><th>Bid order</th><th>Winner</th><th>Bids visible?</th><th>Deposit / fee?</th></tr></thead><tbody><tr><td><a href="#standard">Standard</a></td><td>Ascending</td><td>Highest</td><td>Yes</td><td>None</td></tr><tr><td><a href="#reverse">Reverse</a></td><td>Descending</td><td>Lowest</td><td>Yes</td><td>None</td></tr><tr><td><a href="#sealed">Sealed</a></td><td>Ascending (hidden)</td><td>Highest</td><td>No (until close)</td><td>None</td></tr><tr><td><a href="#proxy">Proxy</a></td><td>Ascending (auto)</td><td>Highest</td><td>Yes</td><td>None</td></tr><tr><td><a href="#silent">Silent</a></td><td>Ascending</td><td>Highest</td><td>At close</td><td>None</td></tr><tr><td><a href="#charity">Charity</a></td><td>Ascending</td><td>Highest</td><td>Yes</td><td>Receipts issued</td></tr><tr><td><a href="#penny">Penny</a></td><td>+1 per bid</td><td>Last before zero</td><td>Yes</td><td>Bid pack purchase</td></tr><tr><td><a href="#dutch">Dutch</a></td><td>Descending price</td><td>First to accept</td><td>Current price visible</td><td>None</td></tr><tr><td><a href="#seated">Seated</a></td><td>Ascending</td><td>Highest paddle</td><td>Yes</td><td>Event registration</td></tr><tr><td><a href="#unique-bid">Unique-Bid</a></td><td>Sealed</td><td>Lowest unique</td><td>No (until close)</td><td>Per-bid fee</td></tr></tbody></table><h2 id="standard" tabindex="-1"><a class="header-anchor" href="#standard"><span>Standard</span></a></h2><p><strong>The default. Highest bidder wins.</strong></p><p>Classic forward auction. Bids go up, the highest one when the timer hits zero (after <a href="/anti-sniping.html" target="_blank" rel="noopener noreferrer">anti-snipe</a> extensions) wins. Reserve must be met or the auction fails.</p><table><thead><tr><th>Field</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td>Start price</td><td>required</td><td>Opening bid</td></tr><tr><td>Reserve price</td><td>optional</td><td>Hidden minimum</td></tr><tr><td>Buy Now</td><td>optional</td><td>Skip-the-line price</td></tr><tr><td>Increment</td><td>required</td><td>Fixed / variable / percentage</td></tr></tbody></table><p>Use for almost everything. Other types are special cases.</p><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-standard-1.png" alt="Standard auction — current price, time remaining, reserve indicator, anti-snipe note, bid form with quick-increment chips, Buy Now and Proxy Bidding"></p><h2 id="reverse" tabindex="-1"><a class="header-anchor" href="#reverse"><span>Reverse</span></a></h2><p><strong>Lowest bid wins.</strong></p><p>Used for procurement, freelancer-pricing, contractor jobs. Bidders compete to undercut. The lowest valid bid at close wins.</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Start price</td><td>Maximum acceptable price (bids must be below)</td></tr><tr><td>Reserve price</td><td>Minimum acceptable; below this auction fails</td></tr><tr><td>Increment</td><td>Decrement amount (e.g., -$10 per bid)</td></tr></tbody></table><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-reverse.png" alt="Reverse auction — bidders compete to undercut the price; lowest valid bid at close wins"></p><h2 id="sealed" tabindex="-1"><a class="header-anchor" href="#sealed"><span>Sealed</span></a></h2><p><strong>Bids hidden until close.</strong></p><p>All-pay style. Bidders see total bid count but never bid amounts. At close, all bids reveal and highest wins. Removes anchoring and bid-war psychology.</p><p>Use for: high-stakes one-shot bids (real estate, art, business sales).</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Reveal at close</td><td>yes (always)</td></tr><tr><td>Show bid count during run</td><td>yes / no toggle</td></tr><tr><td>Allow rebidding</td><td>yes / no toggle</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Anti-snipe doesn&#39;t apply</p><p>Sealed auctions don&#39;t extend on last-second bids — there are no &quot;last seconds&quot; since bids are hidden. End time is final.</p></div><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-sealed-1.png" alt="Sealed-bid auction — bid count is shown but amounts stay hidden until the close-and-reveal"></p><h2 id="proxy" tabindex="-1"><a class="header-anchor" href="#proxy"><span>Proxy</span></a></h2><p><strong>Auto-bidding up to a max.</strong></p><p>Bidder enters their <strong>maximum</strong> willingness to pay. System automatically bids the minimum amount needed to keep them in the lead, only escalating in increments. Stops at the user&#39;s max.</p><p>This is <strong>eBay-style</strong>. Most users default to proxy because it removes the need to constantly check the auction.</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Max bid</td><td>bidder&#39;s secret maximum</td></tr><tr><td>Increment</td><td>min step between auto-bids</td></tr></tbody></table><p>The system stores the max in <code>wkafw_proxy_bids</code> (separate table) — never written to the public bid log until the actual auto-placed bid happens.</p><p><a href="/database.html#table-prefixwkafw_proxy_bids" target="_blank" rel="noopener noreferrer">Proxy table schema →</a></p><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-proxy-1.png" alt="Proxy auction — bidder enters a maximum and the system auto-bids the minimum needed to lead, up to that ceiling"></p><h3 id="how-ties-resolve" tabindex="-1"><a class="header-anchor" href="#how-ties-resolve"><span>How ties resolve</span></a></h3><p>If two bidders enter the same max, the <strong>earliest</strong> registered max wins (timestamp tie-break).</p><h3 id="combined-with-manual" tabindex="-1"><a class="header-anchor" href="#combined-with-manual"><span>Combined with manual</span></a></h3><p>Proxy and manual bids coexist. A proxy bidder is auto-incremented when a manual bidder beats their current bid (until proxy max is hit).</p><h2 id="silent" tabindex="-1"><a class="header-anchor" href="#silent"><span>Silent</span></a></h2><p><strong>Like sealed, but bids reveal during the auction at admin-controlled intervals.</strong></p><p>Used for charity galas (paddle ballots) and event auctions. Admin can schedule reveal windows (&quot;reveals at 4pm sharp&quot;).</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Reveal schedule</td><td>admin-defined times</td></tr><tr><td>Show bid count</td><td>always</td></tr><tr><td>Show top-N</td><td>configurable, e.g. show top 3 only</td></tr></tbody></table><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-silent-1.png" alt="Silent auction — bids accumulate during the auction and reveal in admin-scheduled windows or at close"></p><h2 id="charity" tabindex="-1"><a class="header-anchor" href="#charity"><span>Charity</span></a></h2><p><strong>Standard auction with tax-receipt issuance.</strong></p><p>After the auction sells, the plugin issues a tax-deductible receipt PDF to the buyer (via email + downloadable from My Account). Donor wall optionally lists buyers publicly.</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Charity name</td><td>on receipt</td></tr><tr><td>Charity registration #</td><td>on receipt</td></tr><tr><td>Donor wall enabled</td><td>public list of donors</td></tr><tr><td>Anonymous donation option</td><td>bidder can opt out of donor wall</td></tr><tr><td>Receipt template</td><td>branded PDF</td></tr></tbody></table><p><a href="/compliance.html" target="_blank" rel="noopener noreferrer">Compliance →</a></p><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-charity-1.png" alt="Charity auction — standard bidding flow plus tax-receipt issuance and optional public donor wall"></p><h2 id="penny" tabindex="-1"><a class="header-anchor" href="#penny"><span>Penny</span></a></h2><p><strong>Pay-per-bid model.</strong></p><p>Each bid:</p><ol><li>Costs the bidder one <strong>bid token</strong> (purchased in packs)</li><li>Adds 1¢ (or configurable) to the auction price</li><li>Resets the timer to N seconds (default 10)</li></ol><p>The auction ends when the timer hits zero with no new bid. Last bidder wins. Bidders pay only for bids they placed (token cost), plus the final auction price (cents).</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Pack sizes</td><td>available pack tiers (e.g. 10 / 50 / 200 bids)</td></tr><tr><td>Pack prices</td><td>per pack</td></tr><tr><td>Cents per bid</td><td>how much each bid raises the price</td></tr><tr><td>Timer reset</td><td>seconds added per bid</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Penny auctions are regulated</p><p>Many jurisdictions classify penny auctions as gambling. Verify legality before enabling. The plugin enforces full disclosure: bid pack purchase, per-bid cost, and total spent are all shown to the bidder.</p></div><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-penny-1.png" alt="Penny auction — bid-pack purchase UI, per-bid token cost, timer-reset countdown and current price meter"></p><h2 id="dutch" tabindex="-1"><a class="header-anchor" href="#dutch"><span>Dutch</span></a></h2><p><strong>Descending price; first to accept wins.</strong></p><p>Price starts high and steps down at fixed intervals. The first bidder to click <em>Accept current price</em> wins.</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Start price</td><td>initial high price</td></tr><tr><td>Floor price</td><td>lowest the price will fall to</td></tr><tr><td>Step amount</td><td>currency drop per interval</td></tr><tr><td>Step interval</td><td>seconds between drops</td></tr></tbody></table><p>Used for: time-sensitive perishable goods (fresh fish, fresh flowers, last-minute travel).</p><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-dutch-1.png" alt="Dutch auction — price drops on a fixed schedule and the first bidder to Accept current price wins the lot"></p><h2 id="seated" tabindex="-1"><a class="header-anchor" href="#seated"><span>Seated</span></a></h2><p><strong>Live auctioneer-led format with paddle / seat assignments.</strong></p><p>Bidders register for an event, get assigned a paddle number, and bid via paddle (online or in-person). The admin (auctioneer) controls when each lot opens / closes.</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Event link</td><td>required — must belong to an <a href="/admin-events.html" target="_blank" rel="noopener noreferrer">Event</a></td></tr><tr><td>Seat capacity</td><td>max paddles</td></tr><tr><td>Auctioneer ID</td><td>admin user who controls live actions</td></tr></tbody></table><p>Useful for: real-world live auctions, gala fundraisers, estate sales with online + in-person bidders.</p><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-seated-1.png" alt="Seated auction — paddle / seat assignment, auctioneer-controlled lot lifecycle and live online + in-person bidding"></p><h2 id="unique-bid" tabindex="-1"><a class="header-anchor" href="#unique-bid"><span>Unique-Bid</span></a></h2><p><strong>Lowest unique bid wins.</strong></p><p>Bidders submit secret bids. At close, the system finds the bid amount that no one else placed, and the bidder with the lowest such amount wins.</p><p>Bidders pay a per-bid fee regardless of outcome.</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Per-bid fee</td><td>charged on every submission</td></tr><tr><td>Allow multiple bids per user</td><td>yes / no</td></tr><tr><td>Bid range</td><td>min / max acceptable bid</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Unique-bid is also regulated</p><p>Like penny auctions, this format may be classified as gambling. Verify legality.</p></div><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-unique-bid-1.png" alt="Unique-bid auction — sealed entry, per-bid fee disclosure and lowest-unique-bid win logic"></p><h2 id="switching-types-mid-auction" tabindex="-1"><a class="header-anchor" href="#switching-types-mid-auction"><span>Switching types mid-auction</span></a></h2><p>You <strong>cannot</strong> change auction type once bidding starts — the bid logic differs fundamentally between types. To change, end / cancel the auction and create a new one.</p>',75)])])}]]),r=JSON.parse('{"path":"/auction-types.html","title":"Auction Types","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Quick comparison","slug":"quick-comparison","link":"#quick-comparison","children":[]},{"level":2,"title":"Standard","slug":"standard","link":"#standard","children":[]},{"level":2,"title":"Reverse","slug":"reverse","link":"#reverse","children":[]},{"level":2,"title":"Sealed","slug":"sealed","link":"#sealed","children":[]},{"level":2,"title":"Proxy","slug":"proxy","link":"#proxy","children":[{"level":3,"title":"How ties resolve","slug":"how-ties-resolve","link":"#how-ties-resolve","children":[]},{"level":3,"title":"Combined with manual","slug":"combined-with-manual","link":"#combined-with-manual","children":[]}]},{"level":2,"title":"Silent","slug":"silent","link":"#silent","children":[]},{"level":2,"title":"Charity","slug":"charity","link":"#charity","children":[]},{"level":2,"title":"Penny","slug":"penny","link":"#penny","children":[]},{"level":2,"title":"Dutch","slug":"dutch","link":"#dutch","children":[]},{"level":2,"title":"Seated","slug":"seated","link":"#seated","children":[]},{"level":2,"title":"Unique-Bid","slug":"unique-bid","link":"#unique-bid","children":[]},{"level":2,"title":"Switching types mid-auction","slug":"switching-types-mid-auction","link":"#switching-types-mid-auction","children":[]}],"git":{},"filePathRelative":"auction-types.md"}')}}]);